const stdout = $json.stdout || '';
const start = stdout.indexOf('{');
if (start < 0) {
  return [{ json: { status: 'error', stage: 'collect', message: 'No JSON found in script stdout', raw: stdout, stderr: $json.stderr || '' } }];
}
const parsed = JSON.parse(stdout.slice(start));
return [{ json: { status: 'ok', stage: 'collect', ...parsed, stderr: $json.stderr || '' } }];

