const stdout = $json.stdout || '';
const start = stdout.indexOf('{');
if (start < 0) {
  return [{ json: { status: 'error', stage: 'telegram', message: 'No JSON found in script stdout', raw: stdout, stderr: $json.stderr || '' } }];
}
const parsed = JSON.parse(stdout.slice(start));
return [{ json: { status: 'ok', stage: 'telegram', ...parsed, stderr: $json.stderr || '' } }];

const results = $json.jiraResults || [];
const ticketLinks = results
  .filter((item) => item.issueUrl)
  .map((item) => ({
    key: item.key || '',
    url: item.issueUrl,
    action: item.action,
    priority: item.priority,
    ruleId: item.ruleId,
    agentName: item.agentName,
    aiAnalysis: item.aiAnalysis || 'disabled',
  }));

return [{
  json: {
    ...$json,
    ticketLinks,
    ticketLinkSummary: ticketLinks.length
      ? ticketLinks.map((item) => `${item.priority} ${item.ruleId} ${item.key}: ${item.url} (AI: ${item.aiAnalysis})`).join('\n')
      : 'No Jira ticket links returned. Check JIRA_CREATE_ALERT_TICKETS, Jira credentials, and dedupe settings.',
  },
}];
